"use strict";(self.webpackChunkpos_doc=self.webpackChunkpos_doc||[]).push([[682],{9835(t,e,o){o.r(e),o.d(e,{_pageData:()=>n,default:()=>s});var a=o(641);const n=JSON.parse('{"path":"/woocommerce-pos/admin-configuration.html","title":"Admin Configuration","lang":"en-US","frontmatter":{"title":"Admin Configuration","description":"Configure WooCommerce POS settings including inventory, barcode, web app, WhatsApp, and Node server.","sidebarPosition":5,"navbar":[{"text":"Guide","link":"/guide/"},{"text":"DEMO","link":"https://demo.webkul.com/woocommerce-pos/"},{"text":"PRICING","link":"https://store.webkul.com/woocommerce-pos.html#pricing"},{"text":"POS Add-ons","link":"/add-ons/"}]},"git":{"contributors":[{"name":"himanshu","username":"","email":"himanshu.kumar731@webkul.in","commits":2},{"name":"harshit","username":"","email":"harshit.qa322@webkul.in","commits":2}],"changelog":[{"hash":"e0aac8ca5df6032b25db34a7bd8d20e0c0b22a40","time":1770293899000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated doc"},{"hash":"d40e6fdaa8b21bf16d0e572854cf43f79756c0c7","time":1768918927000,"email":"himanshu.kumar731@webkul.in","author":"himanshu","message":"Added: Update Code for POS doc"},{"hash":"0f78e3256fa0d58de79a9cbca0c15a253149691b","time":1767359090000,"email":"harshit.qa322@webkul.in","author":"harshit","message":"updated content file"},{"hash":"16518591e2894732d0b7035818abb4e0c6f620a6","time":1767082527000,"email":"himanshu.kumar731@webkul.in","author":"himanshu","message":"added initial commit"}]},"filePathRelative":"woocommerce-pos/admin-configuration.md"}'),r={name:"admin-configuration.md"},s=(0,o(6262).A)(r,[["render",function(t,e,o,n,r,s){return(0,a.uX)(),(0,a.CE)("div",null,[...e[0]||(e[0]=[(0,a.Fv)('<h1 id="woocommerce-pos-admin-configuration-settings-guide" tabindex="-1"><a class="header-anchor" href="#woocommerce-pos-admin-configuration-settings-guide"><span>WooCommerce POS - Admin Configuration &amp; Settings Guide</span></a></h1><h1 id="pos-configurations-performed-by-the-admin" tabindex="-1"><a class="header-anchor" href="#pos-configurations-performed-by-the-admin"><span>POS Configurations Performed by the Admin</span></a></h1><p>The POS system provides multiple configuration options that allow the admin to control inventory warnings, order behavior, customer management, payments, appearance, and more. Below is a detailed overview of all available configurations.</p><hr><h2 id="pos-cron-configurations" tabindex="-1"><a class="header-anchor" href="#pos-cron-configurations"><span>POS Cron Configurations</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/poscron-config.webp" alt="Admin-configSettings"></p><p>These settings help administrators manage cash drawer lifecycle operations and automatic reports.</p><table><thead><tr><th style="text-align:left;">Configuration Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Quantity for Low Stock Warning</strong></td><td style="text-align:left;">Enter the minimum quantity threshold to trigger low stock alerts.</td></tr><tr><td style="text-align:left;"><strong>Amount to Increase After Round-Off</strong></td><td style="text-align:left;">Define the amount that will be added after order total round-off.</td></tr><tr><td style="text-align:left;"><strong>Auto Drawer Close</strong></td><td style="text-align:left;">Enable or disable automatic closing of the POS drawer.</td></tr><tr><td style="text-align:left;"><strong>Drawer Auto Close Time</strong></td><td style="text-align:left;">Set the time at which the drawer will automatically close (e.g., <code>12:00 AM</code>).</td></tr><tr><td style="text-align:left;"><strong>Drawer Close Email</strong></td><td style="text-align:left;">Enable or disable email notifications for admins when the drawer is closed.</td></tr><tr><td style="text-align:left;"><strong>Drawer Close Type</strong></td><td style="text-align:left;">Select the method by which the drawer will be closed (manual or automatic).</td></tr></tbody></table><hr><h2 id="order-configuration" tabindex="-1"><a class="header-anchor" href="#order-configuration"><span>Order Configuration</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/orderandstockconfig.webp" alt="Admin-configSettings"></p><p>Configure order-handling rules, offline synchronization, and billing behavior.</p><table><thead><tr><th style="text-align:left;">Configuration Setting</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Quantity for Low Stock Warning</strong></td><td style="text-align:left;">Set the minimum product quantity to trigger low stock warnings.</td></tr><tr><td style="text-align:left;"><strong>Amount to Increase After Round-Off</strong></td><td style="text-align:left;">Define the amount (e.g. <code>5</code>) that will be added after rounding off the order total.</td></tr><tr><td style="text-align:left;"><strong>Auto Sync Offline Orders</strong></td><td style="text-align:left;">Enable to automatically sync offline POS orders once the internet connection is restored.</td></tr><tr><td style="text-align:left;"><strong>Load WooCommerce Orders</strong></td><td style="text-align:left;">Enable or disable syncing of general online WooCommerce orders to POS outlets.</td></tr><tr><td style="text-align:left;"><strong>Order ID Prefix</strong></td><td style="text-align:left;">Enter a custom prefix to be prepended to POS order IDs for distinct sales tracking.</td></tr></tbody></table><hr><h2 id="whatsapp-greetings-settings" tabindex="-1"><a class="header-anchor" href="#whatsapp-greetings-settings"><span>WhatsApp Greetings Settings</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/whatsappgreet.webp" alt="Admin-configSettings"></p><p>Configure how automated customer receipts and greetings are sent via WhatsApp.</p><table><thead><tr><th style="text-align:left;">Setting Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Send WhatsApp Message to Client</strong></td><td style="text-align:left;">Enable to allow sending WhatsApp messages directly from the POS interface.</td></tr><tr><td style="text-align:left;"><strong>Send Order Receipt to Client</strong></td><td style="text-align:left;">Enable to send the order receipt message to the customer via WhatsApp.</td></tr><tr><td style="text-align:left;"><strong>Send Automatic Order Receipt</strong></td><td style="text-align:left;">Enable automatic dispatch of order receipts via WhatsApp immediately upon transaction completion.</td></tr><tr><td style="text-align:left;"><strong>Send Message to Multiple Clients</strong></td><td style="text-align:left;">Enable to authorize broadcasting messages to multiple selected customers.</td></tr></tbody></table><hr><h2 id="barcode-settings" tabindex="-1"><a class="header-anchor" href="#barcode-settings"><span>Barcode Settings</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/barcodesettings.webp" alt="Admin-configSettings"></p><p>Customize the visual output and formatting of product barcode labels.</p><table><thead><tr><th style="text-align:left;">Setting Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Background Color</strong></td><td style="text-align:left;">Select the background color for the barcode label.</td></tr><tr><td style="text-align:left;"><strong>Width</strong></td><td style="text-align:left;">Define the horizontal width/thickness of the barcode lines.</td></tr><tr><td style="text-align:left;"><strong>Display Title</strong></td><td style="text-align:left;">Enable to show the product title/name on the barcode label.</td></tr><tr><td style="text-align:left;"><strong>Height</strong></td><td style="text-align:left;">Set the vertical height of the barcode.</td></tr><tr><td style="text-align:left;"><strong>Text Position</strong></td><td style="text-align:left;">Choose the position of the barcode text (e.g., <code>Top</code> or <code>Bottom</code>).</td></tr><tr><td style="text-align:left;"><strong>Text Size</strong></td><td style="text-align:left;">Define the size of the text displayed with the barcode.</td></tr><tr><td style="text-align:left;"><strong>Print Preview</strong></td><td style="text-align:left;">Preview the barcode layout structure before sending it to the printer.</td></tr></tbody></table><hr><h2 id="customer-details" tabindex="-1"><a class="header-anchor" href="#customer-details"><span>Customer Details</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/customerdetails.webp" alt="Admin-configSettings"></p><p>Admins can add or manage customer information in POS. Below are the configurable fields:</p><ul><li><p><strong>First Name</strong> Default value: <code>default</code></p></li><li><p><strong>Last Name</strong> Default value: <code>customer</code></p></li><li><p><strong>Email</strong> Default value: <code>default.id@webkul.in</code></p></li><li><p><strong>Password</strong> Default value (hashed): <code>$wp$2y$10$ukmMlCUNcdbook4l1hbt8O1mrzK0sRU8nvBrUCLzTe5i23RHLmD6S</code></p></li><li><p><strong>Telephone</strong> Default value: <code>9999999999</code></p></li></ul><h3 id="customer-address" tabindex="-1"><a class="header-anchor" href="#customer-address"><span>Customer Address</span></a></h3><ul><li><p><strong>Company</strong> Enter the customer&#39;s company name (if applicable).</p></li><li><p><strong>Address1</strong> Primary street address.</p></li><li><p><strong>Address2</strong> Secondary street address (optional).</p></li><li><p><strong>City</strong> Customer&#39;s city.</p></li><li><p><strong>Postcode</strong> Customer&#39;s postal code.</p></li><li><p><strong>Country</strong> Customer&#39;s country.</p></li></ul><hr><h2 id="payment-methods" tabindex="-1"><a class="header-anchor" href="#payment-methods"><span>Payment Methods</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/paymentmethod.webp" alt="Admin-configSettings"></p><p>Admins can configure payment methods for record-keeping and checkout purposes.</p><ul><li><p>Click the <strong>Add New</strong> button to create a payment method.</p></li><li><p>Admin can <strong>Edit</strong> or <strong>Delete</strong> existing payment methods.</p></li><li><p>Enter the following details:</p><ul><li>Payment Name</li><li>Payment Slug</li><li>Payment Description</li></ul></li><li><p>Enable or disable payment methods as required.</p></li><li><p>The added payment method must be selected in the respective outlet to be usable.</p></li></ul><hr><h2 id="invoice-printer" tabindex="-1"><a class="header-anchor" href="#invoice-printer"><span>Invoice Printer</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/invoiceprinter.webp" alt="Admin-configSettings"></p><ul><li>Admin can configure printer settings.</li><li>Select and set a <strong>default printer type</strong> for invoice printing.</li></ul><hr><h2 id="appearance-settings" tabindex="-1"><a class="header-anchor" href="#appearance-settings"><span>Appearance Settings</span></a></h2><p><img src="/pos-for-woocommerce/images/woocommerce-pos/appearencesettings.webp" alt="Admin-configSettings"></p><p>Personalize theme elements, product image shapes, and layout styles across the cashier terminal.</p><table><thead><tr><th style="text-align:left;">Visual Configuration</th><th style="text-align:left;">Options / Choices</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>POS Theme Mode</strong></td><td style="text-align:left;"><code>Light</code> / <code>Dark</code></td><td style="text-align:left;">Choose the default theme style for the POS terminal.</td></tr><tr><td style="text-align:left;"><strong>Color Schemes</strong></td><td style="text-align:left;"><em>Dropdown Select</em></td><td style="text-align:left;">Select from predefined color schemes or customize manually.</td></tr><tr><td style="text-align:left;"><strong>Category UI</strong></td><td style="text-align:left;"><code>Old UI</code> / <code>New UI</code></td><td style="text-align:left;">Choose the visual layout style for product categories.</td></tr><tr><td style="text-align:left;"><strong>POS Product Image View</strong></td><td style="text-align:left;"><code>Circle</code> / <code>Square</code> / <code>Rounded</code></td><td style="text-align:left;">Set the shape style of product images on the catalog grid.</td></tr><tr><td style="text-align:left;"><strong>Payment Method Listing Views</strong></td><td style="text-align:left;"><code>Grid View</code> / <code>Grid with Currency</code> / <code>Dropdown</code></td><td style="text-align:left;">Select the layout style of payment methods at checkout.</td></tr><tr><td style="text-align:left;"><strong>Dark Theme</strong></td><td style="text-align:left;"><em>Terminal Override</em></td><td style="text-align:left;">Can be toggled manually by cashiers directly on the front-end screen.</td></tr></tbody></table><hr><h2 id="module-translation" tabindex="-1"><a class="header-anchor" href="#module-translation"><span>Module Translation</span></a></h2><p>Admins can translate the POS module into different languages.</p><ol><li>Save the translation file in the WordPress <code>languages</code> directory.</li><li>Run the following command:</li></ol><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">wp i18n make-json wc_pos-xx_YY.po --no-purge</span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div>',49)])])}]])}}]);